export type FilingStatus = 'single' | 'joint';

export interface TaxBracket {
  min: number;
  max: number;
  rate: number;
}

export interface Deduction {
  id: string;
  type: 'standard' | 'medical' | 'other';
  amount: number;
}

export interface TaxCredit {
  id: string;
  amount: number;
  refundable: boolean;
}

export interface TaxResult {
  grossIncome: number;
  adjustedGrossIncome: number;
  taxableIncome: number;
  regularTax: number;
  amt: number;
  finalTax: number;
  totalCredits: number;
  effectiveRate: number;
  bracketBreakdown: {
    bracket: TaxBracket;
    taxableInBracket: number;
    taxForBracket: number;
  }[];
}

export interface MonthlyTax {
  month: number;
  income: number;
  cumulativeIncome: number;
  cumulativeTax: number;
  brackets: TaxBracket[];
}

export interface TaxCalculatorConfig {
  brackets: { single: TaxBracket[]; joint: TaxBracket[] };
  standardDeduction: { single: number; joint: number };
  standardDeductionPhaseoutStart: { single: number; joint: number };
  amtExemption: { single: number; joint: number };
  amtPhaseoutStart: { single: number; joint: number };
  amtRates: { lowRate: number; lowRateMax: number; highRate: number };
  medicalDeductionFloorRate: number;
}

export class TaxError extends Error {
  constructor(message: string) {
    super(message);
    this.name = 'TaxError';
  }
}

function round2(x: number): number {
  return Math.round(x * 100) / 100;
}

function validateBrackets(brackets: TaxBracket[]): void {
  if (!brackets || brackets.length === 0) {
    throw new TaxError('Brackets must not be empty');
  }
  if (brackets[0].min !== 0) {
    throw new TaxError('Brackets must start at 0');
  }
  if (brackets[brackets.length - 1].max !== Infinity) {
    throw new TaxError('Brackets must end at Infinity');
  }
  for (let i = 1; i < brackets.length; i++) {
    if (brackets[i].min !== brackets[i - 1].max) {
      throw new TaxError('Brackets must be contiguous and sorted');
    }
  }
}

function computeBracketTax(
  income: number,
  brackets: TaxBracket[]
): { total: number; breakdown: TaxResult['bracketBreakdown'] } {
  let total = 0;
  const breakdown: TaxResult['bracketBreakdown'] = [];

  for (const bracket of brackets) {
    const lower = bracket.min;
    const upper = bracket.max === Infinity ? income : bracket.max;
    const taxableInBracket = Math.max(0, Math.min(income, upper) - lower);
    const taxForBracket = round2(taxableInBracket * bracket.rate);
    total += taxForBracket;
    breakdown.push({ bracket, taxableInBracket, taxForBracket });
  }

  return { total, breakdown };
}

function computeStandardDeductionAfterPhaseout(
  grossIncome: number,
  standardDeduction: number,
  phaseoutStart: number
): number {
  if (grossIncome <= phaseoutStart) return standardDeduction;
  const excess = grossIncome - phaseoutStart;
  const units = Math.ceil(excess / 1000);
  const reduction = units * 50;
  return Math.max(0, standardDeduction - reduction);
}

function computeMedicalDeduction(
  grossIncome: number,
  medicalExpenses: number,
  nonMedicalItemized: number,
  floorRate: number
): number {
  if (medicalExpenses === 0) return 0;

  let medDed = 0;
  for (let i = 0; i < 100; i++) {
    const agi = grossIncome - nonMedicalItemized - medDed;
    const floor = floorRate * agi;
    const newMedDed = Math.max(0, medicalExpenses - floor);
    if (Math.abs(newMedDed - medDed) < 0.01) {
      return newMedDed;
    }
    medDed = newMedDed;
  }
  throw new TaxError('Medical deduction did not converge');
}

function applyCredits(
  baseTax: number,
  credits: TaxCredit[]
): { finalTax: number; totalCredits: number } {
  let tax = baseTax;
  let totalCredits = 0;

  // Non-refundable first
  for (const credit of credits.filter((c) => !c.refundable)) {
    const applied = Math.min(credit.amount, Math.max(0, tax));
    tax -= applied;
    totalCredits += applied;
  }

  // Refundable after
  for (const credit of credits.filter((c) => c.refundable)) {
    tax -= credit.amount;
    totalCredits += credit.amount;
  }

  return { finalTax: tax, totalCredits };
}

export function createTaxCalculator(config: TaxCalculatorConfig): {
  setIncome(month: number, amount: number): void;
  setFilingStatus(status: FilingStatus): void;
  addDeduction(deduction: Deduction): void;
  addCredit(credit: TaxCredit): void;
  adjustBrackets(
    brackets: { single: TaxBracket[]; joint: TaxBracket[] },
    fromMonth: number
  ): void;
  calculate(): TaxResult;
  getMonthlyBreakdown(): MonthlyTax[];
} {
  // Validate config brackets
  validateBrackets(config.brackets.single);
  validateBrackets(config.brackets.joint);

  const monthlyIncomes: number[] = new Array(12).fill(0);
  const monthBrackets: Array<{ single: TaxBracket[]; joint: TaxBracket[] }> =
    Array.from({ length: 12 }, () => ({
      single: config.brackets.single,
      joint: config.brackets.joint,
    }));

  let filingStatus: FilingStatus = 'single';
  const deductions: Deduction[] = [];
  const credits: TaxCredit[] = [];

  function setIncome(month: number, amount: number): void {
    if (!Number.isInteger(month) || month < 1 || month > 12) {
      throw new TaxError(`Invalid month: ${month}. Must be an integer between 1 and 12.`);
    }
    if (amount < 0) {
      throw new TaxError('Income must be >= 0');
    }
    monthlyIncomes[month - 1] = amount;
  }

  function setFilingStatus(status: FilingStatus): void {
    if (status !== 'single' && status !== 'joint') {
      throw new TaxError(`Invalid filing status: ${status}`);
    }
    filingStatus = status;
  }

  function addDeduction(deduction: Deduction): void {
    if (deduction.amount < 0) {
      throw new TaxError('Deduction amount must be >= 0');
    }
    deductions.push(deduction);
  }

  function addCredit(credit: TaxCredit): void {
    if (credit.amount < 0) {
      throw new TaxError('Credit amount must be >= 0');
    }
    credits.push(credit);
  }

  function adjustBrackets(
    brackets: { single: TaxBracket[]; joint: TaxBracket[] },
    fromMonth: number
  ): void {
    if (!Number.isInteger(fromMonth) || fromMonth < 1 || fromMonth > 12) {
      throw new TaxError(
        `Invalid fromMonth: ${fromMonth}. Must be an integer between 1 and 12.`
      );
    }
    validateBrackets(brackets.single);
    validateBrackets(brackets.joint);
    for (let m = fromMonth; m <= 12; m++) {
      monthBrackets[m - 1] = brackets;
    }
  }

  function computeDeductionDetails(grossIncome: number): {
    standardAfterPhaseout: number;
    nonMedicalItemized: number;
    medDed: number;
    totalItemized: number;
    usingStandard: boolean;
    chosenDeduction: number;
    taxableIncome: number;
    adjustedGrossIncome: number;
  } {
    const stdDeduction =
      filingStatus === 'single'
        ? config.standardDeduction.single
        : config.standardDeduction.joint;
    const phaseoutStart =
      filingStatus === 'single'
        ? config.standardDeductionPhaseoutStart.single
        : config.standardDeductionPhaseoutStart.joint;

    const standardAfterPhaseout = computeStandardDeductionAfterPhaseout(
      grossIncome,
      stdDeduction,
      phaseoutStart
    );

    const nonMedicalItemized = deductions
      .filter((d) => d.type === 'other')
      .reduce((sum, d) => sum + d.amount, 0);

    const medicalExpenses = deductions
      .filter((d) => d.type === 'medical')
      .reduce((sum, d) => sum + d.amount, 0);

    const medDed = computeMedicalDeduction(
      grossIncome,
      medicalExpenses,
      nonMedicalItemized,
      config.medicalDeductionFloorRate
    );

    const totalItemized = nonMedicalItemized + medDed;
    const usingStandard = standardAfterPhaseout >= totalItemized;
    const chosenDeduction = usingStandard ? standardAfterPhaseout : totalItemized;
    const taxableIncome = Math.max(0, grossIncome - chosenDeduction);
    const adjustedGrossIncome = grossIncome - nonMedicalItemized - medDed;

    return {
      standardAfterPhaseout,
      nonMedicalItemized,
      medDed,
      totalItemized,
      usingStandard,
      chosenDeduction,
      taxableIncome,
      adjustedGrossIncome,
    };
  }

  function computeAMT(
    taxableIncome: number,
    usingStandard: boolean,
    standardAfterPhaseout: number
  ): number {
    // Add back standard deduction if used; itemized not added back
    const amtIncome = usingStandard
      ? taxableIncome + standardAfterPhaseout
      : taxableIncome;

    const exemption =
      filingStatus === 'single'
        ? config.amtExemption.single
        : config.amtExemption.joint;
    const phaseoutStart =
      filingStatus === 'single'
        ? config.amtPhaseoutStart.single
        : config.amtPhaseoutStart.joint;

    const excess = Math.max(0, amtIncome - phaseoutStart);
    const reduction = excess * 0.25;
    const effectiveExemption = Math.max(0, exemption - reduction);

    const amtTaxable = Math.max(0, amtIncome - effectiveExemption);

    const amtBrackets: TaxBracket[] = [
      { min: 0, max: config.amtRates.lowRateMax, rate: config.amtRates.lowRate },
      {
        min: config.amtRates.lowRateMax,
        max: Infinity,
        rate: config.amtRates.highRate,
      },
    ];

    const { total } = computeBracketTax(amtTaxable, amtBrackets);
    return Math.max(0, total);
  }

  function calculate(): TaxResult {
    const grossIncome = monthlyIncomes.reduce((a, b) => a + b, 0);

    if (grossIncome === 0) {
      const { finalTax, totalCredits } = applyCredits(0, credits);
      return {
        grossIncome: 0,
        adjustedGrossIncome: 0,
        taxableIncome: 0,
        regularTax: 0,
        amt: 0,
        finalTax,
        totalCredits,
        effectiveRate: 0,
        bracketBreakdown: [],
      };
    }

    const {
      standardAfterPhaseout,
      nonMedicalItemized,
      medDed,
      usingStandard,
      taxableIncome,
      adjustedGrossIncome,
    } = computeDeductionDetails(grossIncome);

    // Compute regular tax as weighted sum across months
    let regularTax = 0;
    for (let m = 0; m < 12; m++) {
      if (monthlyIncomes[m] === 0) continue;
      const share = monthlyIncomes[m] / grossIncome;
      const monthTaxable = taxableIncome * share;
      const brackets = monthBrackets[m][filingStatus];
      const { total: monthTax } = computeBracketTax(monthTaxable, brackets);
      regularTax += monthTax;
    }

    // Bracket breakdown: use dominant month's brackets applied to full taxable income
    let dominantMonth = 0;
    let maxIncome = -1;
    for (let m = 0; m < 12; m++) {
      if (monthlyIncomes[m] > maxIncome) {
        maxIncome = monthlyIncomes[m];
        dominantMonth = m;
      }
    }
    const repBrackets = monthBrackets[dominantMonth][filingStatus];
    const { breakdown: bracketBreakdown } = computeBracketTax(taxableIncome, repBrackets);

    const amt = computeAMT(taxableIncome, usingStandard, standardAfterPhaseout);
    const baseTax = Math.max(regularTax, amt);
    const { finalTax, totalCredits } = applyCredits(baseTax, credits);

    const effectiveRate = grossIncome === 0 ? 0 : finalTax / grossIncome;

    return {
      grossIncome,
      adjustedGrossIncome,
      taxableIncome,
      regularTax,
      amt,
      finalTax,
      totalCredits,
      effectiveRate,
      bracketBreakdown,
    };
  }

  function getMonthlyBreakdown(): MonthlyTax[] {
    const result: MonthlyTax[] = [];
    let cumulativeIncome = 0;
    let cumulativeTax = 0;

    for (let m = 0; m < 12; m++) {
      const income = monthlyIncomes[m];
      cumulativeIncome += income;

      const annualizedIncome = income * 12;
      let monthlyTax = 0;

      if (annualizedIncome > 0) {
        const { taxableIncome: annualizedTaxable } =
          computeDeductionDetails(annualizedIncome);
        const brackets = monthBrackets[m][filingStatus];
        const { total: annualTax } = computeBracketTax(annualizedTaxable, brackets);
        monthlyTax = annualTax / 12;
      }

      cumulativeTax += monthlyTax;

      result.push({
        month: m + 1,
        income,
        cumulativeIncome,
        cumulativeTax,
        brackets: monthBrackets[m][filingStatus],
      });
    }

    return result;
  }

  return {
    setIncome,
    setFilingStatus,
    addDeduction,
    addCredit,
    adjustBrackets,
    calculate,
    getMonthlyBreakdown,
  };
}

